 /// Compress data in one shot
+/// Compress data in one shot (same as CPython's lzma.compress)
 pub fn compress(allocator: std.mem.Allocator, data: []const u8, format: i32, check: CHECK, preset: ?u32) ![]u8 {
-    _ = format;
